// src/pages/Dashboard.js
import React, { useState } from "react";
import VehicleForm from "../components/VehicleForm";
import VehicleTable from "../components/VehicleTable";

export default function Dashboard() {
  const [refreshKey, setRefreshKey] = useState(0);
  const refreshVehicles = () => setRefreshKey((k) => k + 1);

  return (
    <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 16 }}>
      <div className="card" style={{ gridColumn: "1 / span 1" }}>
        <h3>Live Vehicles</h3>
        <VehicleTable refreshKey={refreshKey} />
      </div>

      <div className="card" style={{ gridColumn: "2 / span 1" }}>
        <h3>Add Vehicle</h3>
        <VehicleForm onCreated={refreshVehicles} />
      </div>

      {/* Optional: Map and Analytics sections remain as in your layout */}
      <div className="card" style={{ gridColumn: "1 / span 1" }}>
        <h3>Map</h3>
        <div style={{ height: 260, background: "#f7f7f7", borderRadius: 8 }} />
      </div>

      <div className="card" style={{ gridColumn: "2 / span 1" }}>
        <h3>Analytics</h3>
        <ul>
          <li>Active: 0</li>
          <li>Idle: 0</li>
          <li>Maintenance: 0</li>
        </ul>
      </div>
    </div>
  );
}
